<template><div class="page-container"><div class="page-card"><div class="header"><h2>简历筛选</h2><p>查看收到的简历、标记流程状态、发起面试或加入人才库。</p></div><el-divider/><el-radio-group v-model="query.status" @change="reload" class="mb-20"><el-radio-button :label="''">全部</el-radio-button><el-radio-button v-for="(t,i) in statusTexts" :key="i" :label="i">{{t}}</el-radio-button></el-radio-group><el-table :data="list" stripe v-loading="loading"><el-table-column prop="id" label="投递ID" width="90"/><el-table-column prop="resumeId" label="简历ID" width="90"/><el-table-column prop="jobId" label="岗位ID" width="90"/><el-table-column prop="applyRemark" label="学生附言" min-width="180" show-overflow-tooltip/><el-table-column label="状态" width="120"><template #default="{row}"><el-tag :type="type(row.status)">{{statusTexts[row.status]}}</el-tag></template></el-table-column><el-table-column prop="createTime" label="投递时间" width="180"/><el-table-column label="操作" width="320"><template #default="{row}"><el-button text type="primary" @click="view(row)">查看</el-button><el-dropdown @command="s=>setStatus(row,s)"><el-button text>标记状态<el-icon><ArrowDown/></el-icon></el-button><template #dropdown><el-dropdown-menu><el-dropdown-item v-for="(t,i) in statusTexts" :key="i" :command="i">{{t}}</el-dropdown-item></el-dropdown-menu></template></el-dropdown><el-button text type="success" @click="openInterview(row)">邀面试</el-button></template></el-table-column></el-table><div class="pagination-wrap"><el-pagination v-model:current-page="query.pageNum" :total="total" background layout="total,prev,pager,next" @current-change="load"/></div></div><el-dialog v-model="detailDialog" title="投递详情" width="560px"><el-descriptions :column="1" border v-if="detail"><el-descriptions-item label="投递ID">{{detail.id}}</el-descriptions-item><el-descriptions-item label="学生ID">{{detail.studentId}}</el-descriptions-item><el-descriptions-item label="简历ID">{{detail.resumeId}}</el-descriptions-item><el-descriptions-item label="岗位ID">{{detail.jobId}}</el-descriptions-item><el-descriptions-item label="状态"><el-tag>{{statusTexts[detail.status]}}</el-tag></el-descriptions-item><el-descriptions-item label="附言">{{detail.applyRemark||'-'}}</el-descriptions-item></el-descriptions></el-dialog><el-dialog v-model="interviewDialog" title="发送面试邀请" width="620px"><el-form :model="interview" label-width="100px"><el-form-item label="面试时间"><el-date-picker v-model="interview.interviewTime" type="datetime" value-format="YYYY-MM-DD HH:mm:ss" style="width:100%"/></el-form-item><el-form-item label="面试方式"><el-radio-group v-model="interview.interviewType"><el-radio :label="1">现场</el-radio><el-radio :label="2">线上</el-radio></el-radio-group></el-form-item><el-form-item label="地点/链接"><el-input v-model="interview.location"/></el-form-item><el-form-item label="联系人"><el-input v-model="interview.contact"/></el-form-item><el-form-item label="备注"><el-input v-model="interview.remark" type="textarea" :rows="3"/></el-form-item></el-form><template #footer><el-button @click="interviewDialog=false">取消</el-button><el-button type="primary" @click="sendInterview">发送</el-button></template></el-dialog></div></template>
<script setup>import{reactive,ref,onMounted}from'vue';import{ElMessage}from'element-plus';import{ArrowDown}from'@element-plus/icons-vue';import{enterpriseApi}from'@/api';const statusTexts=['待查看','已查看','邀请面试','笔试','已录用','不合适'];const type=s=>s===4?'success':s===5?'danger':s>=2?'warning':'info';const query=reactive({pageNum:1,pageSize:10,status:''});const list=ref([]),total=ref(0),loading=ref(false),detailDialog=ref(false),interviewDialog=ref(false),detail=ref(null);const interview=reactive({});const load=async()=>{loading.value=true;try{const p={pageNum:query.pageNum,pageSize:query.pageSize};if(query.status!=='')p.status=query.status;const r=await enterpriseApi.applyList(p);list.value=r.data.records;total.value=Number(r.data.total)}finally{loading.value=false}};const reload=()=>{query.pageNum=1;load()};const view=async row=>{detail.value=(await enterpriseApi.applyDetail(row.id)).data;detailDialog.value=true;load()};const setStatus=async(row,s)=>{await enterpriseApi.updateApplyStatus(row.id,s,'HR已更新流程状态');ElMessage.success('状态已更新');load()};const openInterview=row=>{Object.keys(interview).forEach(k=>delete interview[k]);Object.assign(interview,{applyId:row.id,studentId:row.studentId,jobId:row.jobId,interviewType:1});interviewDialog.value=true};const sendInterview=async()=>{await enterpriseApi.sendInterview(interview);ElMessage.success('面试邀请已发送');interviewDialog.value=false;load()};onMounted(load)</script>
<style scoped>.header h2{margin-bottom:6px}.header p{color:#909399}</style>